const token = $json.headers["x-session-token"];
const apiKey = $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY;
const baseId = $env.AIRTABLE_BASE_ID;

if (!token) return { json: { statusCode: 401, error: "expired", code: "session_missing" } };
if (!apiKey || !baseId) {
  return { json: { statusCode: 500, error: "Airtable env vars missing", code: "airtable_config_missing" } };
}

const airtable = `https://api.airtable.com/v0/${baseId}`;
const formula = `AND({session_token} = '${token.replace(/'/g, "\\'")}', IS_AFTER({session_expires_at}, NOW()))`;
const url = `${airtable}/Users?maxRecords=1&filterByFormula=${encodeURIComponent(formula)}`;

const res = await fetch(url, { headers: { Authorization: `Bearer ${apiKey}` } });
if (!res.ok) {
  return { json: { statusCode: 500, error: "Airtable user lookup failed", code: "airtable_users_failed" } };
}

const data = await res.json();
const record = data.records?.[0];
if (!record) return { json: { statusCode: 401, error: "expired", code: "session_invalid" } };

return {
  json: {
    session: {
      airtable_id: record.id,
      id: record.fields.id || record.id,
      name: record.fields.name,
      role: record.fields.role,
    },
    body: $json.body,
  },
};

const apiKey = $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY;
const baseId = $env.AIRTABLE_BASE_ID;
const session = $json.session;
const body = $json.body || {};

if (!session || !["samuel", "mathilde"].includes(session.role)) {
  return [{ json: { statusCode: 403, error: "forbidden", code: "episode_create_forbidden" } }];
}

const title = String(body.title || "").trim();
const date = String(body.date || "").trim();
const place = String(body.place || "").trim();
const duration = String(body.duration || "").trim();
const coverUrl = String(body.cover_url || "").trim();
const tags = Array.isArray(body.tags)
  ? body.tags.map((tag) => String(tag).trim()).filter(Boolean)
  : [];

if (!title || !date || !place) {
  return [{ json: { statusCode: 400, error: "title, date and place are required", code: "episode_invalid" } }];
}

const airtable = `https://api.airtable.com/v0/${baseId}`;
const headers = {
  Authorization: `Bearer ${apiKey}`,
  "Content-Type": "application/json",
};

const listRes = await fetch(`${airtable}/Episodes?fields%5B%5D=number&sort%5B0%5D%5Bfield%5D=number&sort%5B0%5D%5Bdirection%5D=desc&maxRecords=1`, { headers });
if (!listRes.ok) {
  return [{ json: { statusCode: 500, error: "Airtable episodes lookup failed", code: "airtable_episodes_failed" } }];
}
const listData = await listRes.json();
const maxNumber = Number(listData.records?.[0]?.fields?.number || 0);
const number = maxNumber + 1;

const fields = { title, date, place, number };
if (duration) fields.duration = duration;
if (coverUrl) fields.cover_url = coverUrl;
if (tags.length) fields.tags = tags;

const createRes = await fetch(`${airtable}/Episodes`, {
  method: "POST",
  headers,
  body: JSON.stringify({ fields }),
});

const created = await createRes.json();
if (!createRes.ok) {
  return [{ json: { statusCode: 500, error: created.error?.message || "Airtable episode create failed", code: "airtable_episode_create_failed" } }];
}

const f = created.fields;
return [{
  json: {
    episode: {
      id: f.id || created.id,
      number: f.number,
      title: f.title,
      date: f.date,
      place: f.place,
      duration: f.duration || "",
      tags: f.tags || [],
      cover_url: f.cover_url || "",
    },
  },
}];
